import org.junit.jupiter.api.Test;

class DefaultEvaluationStrategyJoinEngineRuntimeFeedbackTest {

	@Test
	void reportsRuntimeBanditRewardOnIterationClose() throws Exception {
		System.setProperty("rdf4j.optimizer.joinengine.runtimeFeedback.enabled", "true");
		try {
			String query = String.join("\n",
					"PREFIX ex: <http://example.com/>",
					"SELECT * WHERE {",
					"  ?s ex:p1 ?o .",
					"  ?o ex:p2 ?x .",
					"}");

			ParsedQuery parsed = new SPARQLParser().parseQuery(query, null);
			TupleExpr expr = parsed.getTupleExpr();

			RecordingBanditPolicy bandit = new RecordingBanditPolicy();
			QueryJoinOptimizer optimizer = new QueryJoinOptimizer(new EvaluationStatistics(), false,
					new EmptyTripleSource(), true, JoinEngineConfig.defaults(), new DefaultJoinOptimizationEngine(),
					new DefaultUncertaintyAwareEstimator(), new DefaultCostModel(), bandit, OptimizationTraceSink.NOOP);

			optimizer.optimize(expr, null, EmptyBindingSet.getInstance());
			assertThat(bandit.reports).isEmpty();

			DefaultEvaluationStrategy strategy = new DefaultEvaluationStrategy(new EmptyTripleSource(), null, null, 0L,
					new EvaluationStatistics());
			try (CloseableIteration<BindingSet> result = strategy.precompile(expr)
					.evaluate(EmptyBindingSet.getInstance())) {
				while (result.hasNext()) {
					result.next();
				}
			}

			assertThat(bandit.reports).hasSize(1);
			ReportedOutcome first = bandit.reports.get(0);
			assertThat(first.regionFingerprint).isNotBlank();
			assertThat(first.planner).isNotBlank();
			assertThat(first.reward).isLessThanOrEqualTo(-1.0d);
		} finally {
			System.clearProperty("rdf4j.optimizer.joinengine.runtimeFeedback.enabled");
			org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine.JoinEngineRuntimeFeedback
					.clearCurrentThread();
		}
	}

	private static final class RecordingBanditPolicy implements BanditPolicy {
		private final List<ReportedOutcome> reports = new CopyOnWriteArrayList<>();

		@Override
		public List<String> selectPlanners(String regionFingerprint, List<String> available, int k) {
			return available.subList(0, Math.max(1, Math.min(k, available.size())));
		}

		@Override
		public void reportOutcome(String regionFingerprint, String chosenPlanner, double reward) {
			reports.add(new ReportedOutcome(regionFingerprint, chosenPlanner, reward));
		}
	}

	private record ReportedOutcome(String regionFingerprint, String planner, double reward) {
	}
}
